class Solution:
    def search(self, arr: list[int], n: int, target: int) -> int:
        left, right = 0, n - 1
        while left <= right:
            mid = left + (right - left) // 2
            if arr[mid] == target:
                if mid == 0 or arr[mid - 1] != target:
                    return mid
                right = mid - 1
            elif arr[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return -1

if __name__ == '__main__':
    solver = Solution()
    n = int(input())
    arr = [int(x) for x in input().split()]
    target = int(input())
    print(solver.search(arr, n, target))

